Chat Edit: '**Diagnosis:** Qt purge broke the HTTP transport layer. `QNetworkAccessManager` was ripped out but the WinHTTP replacement isn't wired to the new STL-based agent core.

**Immediate Fix:**

### 1. Verify Ollama is Alive
```powershell
curl http://localhost:11434/api/tags
# Must return JSON with bigdaddyg-fast in list
# If dead: Start-Service ollama (or ollama serve)
```

### 2. HTTP Client Post-Qt Fix
During Qt purge, `QNetworkReply` → `WinHTTP` transition likely lost the async callback. Patch your agent HTTP client:

```cpp
// src/agent/llm_http_client.cpp (post-Qt)
#include <windows.h>
#include <winhttp.h>
#include <future>
#include <sstream>

#pragma comment(lib, "winhttp.lib")

class StlHttpClient {
    std::wstring m_host = L"localhost";
    INTERNET_PORT m_port = 11434;
    
public:
    std::future<std::string> fetch(const std::string& path, 
                                   const std::string& jsonBody) {
        return std::async(std::launch::async, [=]() -> std::string {
            HINTERNET hSession = WinHttpOpen(L"RawrXD-Agent/1.0", 
                WINHTTP_ACCESS_TYPE_DEFAULT_PROXY, NULL, NULL, 0);
            if (!hSession) throw std::runtime_error("WinHttpOpen failed");
            
            HINTERNET hConnect = WinHttpConnect(hSession, m_host.c_str(), m_port, 0);
            HINTERNET hRequest = WinHttpOpenRequest(hConnect, L"POST", 
                std::wstring(path.begin(), path.end()).c_str(),
                NULL, WINHTTP_NO_REFERER, 
                WINHTTP_DEFAULT_ACCEPT_TYPES, 0);
            
            std::string headers = "Content-Type: application/json";
            WinHttpSendRequest(hRequest, 
                std::wstring(headers.begin(), headers.end()).c_str(), -1,
                (LPVOID)jsonBody.c_str(), jsonBody.length(), 
                jsonBody.length(), 0);
            
            WinHttpReceiveResponse(hRequest, NULL);
            
            std::string response;
            DWORD bytesRead;
            char buffer[4096];
            while (WinHttpReadData(hRequest, buffer, sizeof(buffer), &bytesRead) 
                   && bytesRead > 0) {
                response.append(buffer, bytesRead);
            }
            
            WinHttpCloseHandle(hRequest);
            WinHttpCloseHandle(hConnect);
            WinHttpCloseHandle(hSession);
            return response;
        });
    }
};
```

### 3. Chain-of-Thought Specific Fix
The error suggests the Reviewer step's HTTP future is being destroyed before completion (Qt's event loop hid this).

**In your ChainExecutor:**
```cpp
// Before (Qt): reply->deleteLater() handled cleanup
// After (STL): Must hold future until completion

class ChainStep {
    std::future<std::string> m_future;  // KEEP THIS ALIVE
    std::string m_result;
    
public:
    void start(const std::string& prompt) {
        StlHttpClient client;
        json body = {{"model", "bigdaddyg-fast:latest"}, 
                     {"prompt", prompt}, {"stream", false}};
        m_future = client.fetch("/api/generate", body.dump());
    }
    
    bool poll() {
        if (!m_future.valid()) return false;
        if (m_future.wait_for(std::chrono::milliseconds(0)) 
            == std::future_status::ready) {
            m_result = m_future.get();
            return true;
        }
        return false;
    }
};
```

### 4. Model Name Verification
```powershell
ollama list | findstr bigdaddyg
# If empty: ollama pull bigdaddyg-fast:latest
```

**If still failing after WinHTTP fix:** Check that `agent/` directory's HTTP includes were added to CMake:
```cmake
target_link_libraries(agent PRIVATE winhttp.lib)
```

**Root cause:** Qt's signal-slot auto-managed the reply lifetime. STL futures require explicit retention or they destruct-cancel the async operation → "Failed to fetch".

Fix the lifetime, fix the fetch.'
